from flask import Flask, request, jsonify
import psycopg2
from psycopg2 import sql, extras
from contextlib import contextmanager
import re
from typing import Dict, List, Any, Optional

app = Flask(__name__)

DB_CONFIG = {
    'host': 'localhost',
    'database': 'analytics_db',
    'user': 'your_username',
    'password': 'your_password',
    'port': 5432
}

ALLOWED_TABLES = [
    'users', 'orders', 'products', 'transactions', 
    'customers', 'sales', 'inventory', 'analytics'
]

ALLOWED_OPERATORS = ['=', '!=', '>', '<', '>=', '<=', 'LIKE', 'ILIKE', 'IN', 'NOT IN', 'IS NULL', 'IS NOT NULL']

@contextmanager
def get_db_connection():
    conn = None
    try:
        conn = psycopg2.connect(**DB_CONFIG)
        yield conn
    finally:
        if conn:
            conn.close()

def validate_identifier(identifier: str) -> bool:
    return bool(re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', identifier))

def validate_table_name(table_name: str) -> bool:
    return table_name in ALLOWED_TABLES and validate_identifier(table_name)

def validate_column_name(column_name: str) -> bool:
    return validate_identifier(column_name)

def build_where_clause(filters: List[Dict[str, Any]]) -> tuple:
    conditions = []
    params = []
    
    for filter_item in filters:
        column = filter_item.get('column')
        operator = filter_item.get('operator', '=').upper()
        value = filter_item.get('value')
        
        if not validate_column_name(column):
            raise ValueError(f"Invalid column name: {column}")
        
        if operator not in ALLOWED_OPERATORS:
            raise ValueError(f"Invalid operator: {operator}")
        
        if operator in ['IS NULL', 'IS NOT NULL']:
            conditions.append(sql.SQL("{} {}").format(
                sql.Identifier(column),
                sql.SQL(operator)
            ))
        elif operator in ['IN', 'NOT IN']:
            if not isinstance(value, list):
                raise ValueError(f"Value for {operator} must be a list")
            placeholders = sql.SQL(', ').join([sql.Placeholder()] * len(value))
            conditions.append(sql.SQL("{} {} ({})").format(
                sql.Identifier(column),
                sql.SQL(operator),
                placeholders
            ))
            params.extend(value)
        else:
            conditions.append(sql.SQL("{} {} {}").format(
                sql.Identifier(column),
                sql.SQL(operator),
                sql.Placeholder()
            ))
            params.append(value)
    
    return conditions, params

def build_order_clause(order_by: List[Dict[str, str]]) -> sql.Composable:
    order_parts = []
    
    for order_item in order_by:
        column = order_item.get('column')
        direction = order_item.get('direction', 'ASC').upper()
        
        if not validate_column_name(column):
            raise ValueError(f"Invalid column name: {column}")
        
        if direction not in ['ASC', 'DESC']:
            raise ValueError(f"Invalid sort direction: {direction}")
        
        order_parts.append(sql.SQL("{} {}").format(
            sql.Identifier(column),
            sql.SQL(direction)
        ))
    
    return sql.SQL(', ').join(order_parts)

@app.route('/api/query', methods=['POST'])
def query_data():
    try:
        data = request.get_json()
        
        table_name = data.get('table')
        columns = data.get('columns', ['*'])
        filters = data.get('filters', [])
        order_by = data.get('order_by', [])
        limit = data.get('limit')
        offset = data.get('offset')
        
        if not validate_table_name(table_name):
            return jsonify({'error': f'Invalid or unauthorized table name: {table_name}'}), 400
        
        if columns != ['*']:
            for col in columns:
                if not validate_column_name(col):
                    return jsonify({'error': f'Invalid column name: {col}'}), 400
            column_clause = sql.SQL(', ').join([sql.Identifier(col) for col in columns])
        else:
            column_clause = sql.SQL('*')
        
        query = sql.SQL("SELECT {} FROM {}").format(
            column_clause,
            sql.Identifier(table_name)
        )
        
        params = []
        
        if filters:
            conditions, filter_params = build_where_clause(filters)
            params.extend(filter_params)
            query = sql.SQL("{} WHERE {}").format(
                query,
                sql.SQL(' AND ').join(conditions)
            )
        
        if order_by:
            order_clause = build_order_clause(order_by)
            query = sql.SQL("{} ORDER BY {}").format(query, order_clause)
        
        if limit is not None:
            if not isinstance(limit, int) or limit < 0:
                return jsonify({'error': 'Invalid limit value'}), 400
            query = sql.SQL("{} LIMIT {}").format(query, sql.Placeholder())
            params.append(limit)
        
        if offset is not None:
            if not isinstance(offset, int) or offset < 0:
                return jsonify({'error': 'Invalid offset value'}), 400
            query = sql.SQL("{} OFFSET {}").format(query, sql.Placeholder())
            params.append(offset)
        
        with get_db_connection() as conn:
            with conn.cursor(cursor_factory=extras.RealDictCursor) as cursor:
                cursor.execute(query, params)
                results = cursor.fetchall()
                
                return jsonify({
                    'success': True,
                    'data': results,
                    'count': len(results)
                }), 200
                
    except ValueError as e:
        return jsonify({'error': str(e)}), 400
    except psycopg2.Error as e:
        return jsonify({'error': f'Database error: {str(e)}'}), 500
    except Exception as e:
        return jsonify({'error': f'Internal server error: {str(e)}'}), 500

@app.route('/api/aggregate', methods=['POST'])
def aggregate_data():
    try:
        data = request.get_json()
        
        table_name = data.get('table')
        aggregations = data.get('aggregations', [])
        group_by = data.get('group_by', [])
        filters = data.get('filters', [])
        having = data.get('having', [])
        
        if not validate_table_name(table_name):
            return jsonify({'error': f'Invalid or unauthorized table name: {table_name}'}), 400
        
        select_parts = []
        
        for agg in aggregations:
            func = agg.get('function', '').upper()
            column = agg.get('column')
            alias = agg.get('alias')
            
            if func not in ['COUNT', 'SUM', 'AVG', 'MIN', 'MAX']:
                return jsonify({'error': f'Invalid aggregation function: {func}'}), 400
            
            if column != '*' and not validate_column_name(column):
                return jsonify({'error': f'Invalid column name: {column}'}), 400
            
            if alias and not validate_identifier(alias):
                return jsonify({'error': f'Invalid alias: {alias}'}), 400
            
            if column == '*':
                agg_expr = sql.SQL("{}(*)").format(sql.SQL(func))
            else:
                agg_expr = sql.SQL("{}({})").format(sql.SQL(func), sql.Identifier(column))
            
            if alias:
                agg_expr = sql.SQL("{} AS {}").format(agg_expr, sql.Identifier(alias))
            
            select_parts.append(agg_expr)
        
        for col in group_by:
            if not validate_column_name(col):
                return jsonify({'error': f'Invalid column name: {col}'}), 400
            select_parts.append(sql.Identifier(col))
        
        if not select_parts:
            return jsonify({'error': 'No aggregations or group by columns specified'}), 400
        
        query = sql.SQL("SELECT {} FROM {}").format(
            sql.SQL(', ').join(select_parts),
            sql.Identifier(table_name)
        )
        
        params = []
        
        if filters:
            conditions, filter_params = build_where_clause(filters)
            params.extend(filter_params)
            query = sql.SQL("{} WHERE {}").format(
                query,
                sql.SQL(' AND ').join(conditions)
            )
        
        if group_by:
            group_clause = sql.SQL(', ').join([sql.Identifier(col) for col in group_by])
            query = sql.SQL("{} GROUP BY {}").format(query, group_clause)
        
        if having:
            having_conditions, having_params = build_where_clause(having)
            params.extend(having_params)
            query = sql.SQL("{} HAVING {}").format(
                query,
                sql.SQL(' AND ').join(having_conditions)
            )
        
        with get_db_connection() as conn:
            with conn.cursor(cursor_factory=extras.RealDictCursor) as cursor:
                cursor.execute(query, params)
                results = cursor.fetchall()
                
                return jsonify({
                    'success': True,
                    'data': results,
                    'count': len(results)
                }), 200
                
    except ValueError as e:
        return jsonify({'error': str(e)}), 400
    except psycopg2.Error as e:
        return jsonify({'error': f'Database error: {str(e)}'}), 500
    except Exception as e:
        return jsonify({'error': f'Internal server error: {str(e)}'}), 500

