            on_condition = join.get('on')
            
            if join_type not in ['INNER', 'LEFT', 'RIGHT', 'FULL']:
                return jsonify({'error': f'Invalid join type: {join_type}'}), 400
            
            if not validate_table_name(join_table):
                return jsonify({'error': f'Invalid table name: {join_table}'}), 400
            
            if not validate_identifier(join_alias):
                return jsonify({'error': f'Invalid alias: {join_alias}'}), 400
            
            left_col = on_condition.get('left')
